import React, { useEffect, useState } from 'react';
import { useLocation, useNavigate, Link } from 'react-router-dom';

const RelatedPage = ({ restaurants }) => {
  const location = useLocation();
  const navigate = useNavigate();
  const [selectedRestaurant, setSelectedRestaurant] = useState(null);
  const [relatedRestaurants, setRelatedRestaurants] = useState([]);

  useEffect(() => {
    const params = new URLSearchParams(location.search);
    const restaurantId = parseInt(params.get('id'));
    
    if (restaurantId && restaurants.length > 0) {
      const restaurant = restaurants.find(r => r.id === restaurantId);
      if (restaurant) {
        setSelectedRestaurant(restaurant);
        const related = findRelatedRestaurants(restaurant, restaurants);
        setRelatedRestaurants(related);
      }
    }
  }, [location.search, restaurants]);

  const findRelatedRestaurants = (restaurant, allRestaurants) => {
    const cuisineTypes = restaurant.cuisine.split(',').map(c => c.trim().toLowerCase());
    const scored = allRestaurants
      .filter(r => r.id !== restaurant.id)
      .map(r => {
        let score = 0;
        const rCuisines = r.cuisine.split(',').map(c => c.trim().toLowerCase());
        cuisineTypes.forEach(c => {
          rCuisines.forEach(rc => {
            if (rc.includes(c) || c.includes(rc)) {
              score += 2;
            }
          });
        });
        return { restaurant: r, score };
      })
      .filter(item => item.score > 0)
      .sort((a, b) => b.score - a.score);
    
    const related = scored.slice(0, Math.max(20, scored.length));
    if (related.length < 20) {
      const usedIds = new Set([restaurant.id, ...related.map(r => r.restaurant.id)]);
      const remaining = allRestaurants.filter(r => !usedIds.has(r.id)).slice(0, 20 - related.length);
      return [...related.map(r => r.restaurant), ...remaining];
    }
    return related.map(item => item.restaurant);
  };

  const handleCardClick = (restaurant) => {
    navigate(`/related?id=${restaurant.id}`);
  };

  const goBack = () => {
    navigate('/');
  };

  if (!selectedRestaurant) {
    return (
      <div className="loading-page">
        <p>Loading...</p>
      </div>
    );
  }

  return (
    <div className="related-page">
      {/* Header */}
      <header className="header">
        <div className="header-top">
          <Link to="/" className="logo">
            <div className="logo-icon">
              <i className="fas fa-carrot"></i>
            </div>
            Yeswanth's Healthy Kitchen
          </Link>
        </div>
      </header>

      {/* Back Button */}
      <div className="page-actions">
        <button className="back-btn" onClick={goBack}>
          <i className="fas fa-arrow-left"></i> Back to Home
        </button>
      </div>

      {/* Related Restaurants Content */}
      <main className="main-content">
        <div className="related-header">
          <h2>More from {selectedRestaurant.name}</h2>
          <p>Cuisine: {selectedRestaurant.cuisine}</p>
          <p className="related-count">Showing {relatedRestaurants.length} related restaurants</p>
        </div>
        
        <div className="restaurant-grid">
          {relatedRestaurants.map(restaurant => (
            <div 
              className="restaurant-card" 
              key={restaurant.id}
              onClick={() => handleCardClick(restaurant)}
            >
              <div className="restaurant-image">
                <img src={restaurant.image} alt={restaurant.name} />
                <div className="discount-badge">{restaurant.discount}</div>
              </div>
              <div className="restaurant-info">
                <div className="restaurant-name">{restaurant.name}</div>
                <div className="restaurant-cuisine">{restaurant.cuisine}</div>
                <div className="restaurant-details">
                  <span className="rating">★ {restaurant.rating}</span>
                  <span className="delivery-time">⏱ {restaurant.deliveryTime}</span>
                </div>
              </div>
            </div>
          ))}
        </div>
      </main>

      {/* Footer */}
      <footer className="footer">
        <div className="footer-bottom">
          <p>© 2024 Yeswanth's Healthy Kitchen - All rights reserved</p>
        </div>
      </footer>
    </div>
  );
};

export default RelatedPage;
